package com.nattechnologies.trastcms.plugins.saas;
import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/public/saas") class SaasPublicController{private final SaasService s;SaasPublicController(SaasService s){this.s=s;}@GetMapping("/products/{productKey}/plans")List<SaasDtos.PlanResponse>plans(@PathVariable String productKey){return s.publicPlans(productKey);}@PostMapping("/licenses/validate")SaasDtos.LicenseResult validate(@Valid@RequestBody SaasDtos.LicenseRequest r){return s.validate(r,false);}@PostMapping("/licenses/activate")SaasDtos.LicenseResult activate(@Valid@RequestBody SaasDtos.LicenseRequest r){return s.validate(r,true);}@PostMapping("/licenses/heartbeat")SaasDtos.LicenseResult heartbeat(@Valid@RequestBody SaasDtos.LicenseRequest r){return s.heartbeat(r);}@PostMapping("/licenses/deactivate")@ResponseStatus(HttpStatus.NO_CONTENT)void deactivate(@Valid@RequestBody SaasDtos.DeactivateRequest r){s.deactivate(r);}@PostMapping("/usage")Map<String,Object>usage(@Valid@RequestBody SaasDtos.UsageRequest r){return s.usage(r);}@GetMapping("/orders/{orderNumber}/claim")SaasDtos.ClaimResponse claim(@PathVariable String orderNumber,@RequestParam String token){return s.claim(orderNumber,token);}@PostMapping("/releases/latest")SaasDtos.ReleaseResponse latest(@RequestParam String productKey,@RequestParam String platform,@RequestParam(defaultValue="stable")String channel,@Valid@RequestBody SaasDtos.LicenseRequest r){return s.latest(productKey,platform,channel,r);}}
@RestController @RequestMapping("/api/admin/saas") class SaasAdminController{private final SaasService s;SaasAdminController(SaasService s){this.s=s;}@GetMapping("/dashboard")SaasDtos.Dashboard dashboard(){return s.dashboard();}@GetMapping("/products")List<SaasDtos.ProductResponse>products(){return s.products();}@PostMapping("/products")@ResponseStatus(HttpStatus.CREATED)SaasDtos.ProductResponse product(@Valid@RequestBody SaasDtos.ProductRequest r){return s.saveProduct(null,r);}@PutMapping("/products/{id}")SaasDtos.ProductResponse product(@PathVariable String id,@Valid@RequestBody SaasDtos.ProductRequest r){return s.saveProduct(id,r);}@GetMapping("/plans")List<SaasDtos.PlanResponse>plans(){return s.plans();}@PostMapping("/plans")@ResponseStatus(HttpStatus.CREATED)SaasDtos.PlanResponse plan(@Valid@RequestBody SaasDtos.PlanRequest r){return s.savePlan(null,r);}@PutMapping("/plans/{id}")SaasDtos.PlanResponse plan(@PathVariable String id,@Valid@RequestBody SaasDtos.PlanRequest r){return s.savePlan(id,r);}@GetMapping("/licenses")List<SaasDtos.LicenseResponse>licenses(){return s.licenses();}@PostMapping("/licenses")@ResponseStatus(HttpStatus.CREATED)SaasDtos.LicenseResponse issue(@Valid@RequestBody SaasDtos.IssueLicenseRequest r){return s.issue(r);}@GetMapping("/subscriptions")List<SaasDtos.SubscriptionResponse>subscriptions(){return s.subscriptions();}@PostMapping("/releases")@ResponseStatus(HttpStatus.CREATED)SaasDtos.ReleaseResponse release(@Valid@RequestBody SaasDtos.ReleaseRequest r){return s.saveRelease(null,r);}}
